import React from 'react';

export const CloudIcon: React.FC<{ className?: string }> = ({ className = "h-5 w-5" }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" />
    </svg>
);

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { parseTransactionsFromText } from './services/geminiService';
import { parseWithRules } from './services/ruleBasedParsers';
import { Transaction, Expense, UnparseableTransaction, Budgets, CustomParser, AppData, AiConfirmationItem, RoadmapItem } from './types';
import TransactionCard from './components/TransactionCard';
import UnparseableTransactionCard from './components/UnparseableTransactionCard';
import AiConfirmationCard from './components/AiConfirmationCard';
import ExpenseSummary from './components/ExpenseSummary';
import ExpenseChart from './components/ExpenseChart';
import { CheckCircleIcon } from './components/icons/CheckCircleIcon';
import { SettingsIcon } from './components/icons/SettingsIcon';
import { PlusIcon } from './components/icons/PlusIcon';
import { LogIcon } from './components/icons/LogIcon';
import MessageProcessor from './components/MessageProcessor';
import LogViewer from './components/LogViewer';
import BudgetStatus from './components/BudgetStatus';
import EmptyState from './components/EmptyState';
import { DEFAULT_EXPENSE_CATEGORIES } from './constants';
import { getWeeksInMonth, formatDateRange } from './utils/dateUtils';
import { ChevronLeftIcon } from './components/icons/ChevronLeftIcon';
import { ChevronRightIcon } from './components/icons/ChevronRightIcon';
import { logService } from './services/logService';
import Settings from './components/Settings';
import Trends from './components/Trends';
import { TrendingUpIcon } from './components/icons/TrendingUpIcon';
import ReceiptScanner from './components/ReceiptScanner';
import { LogoIcon } from './components/icons/LogoIcon';
import { SpinnerIcon } from './components/icons/SpinnerIcon';
import { DownloadIcon } from './components/icons/DownloadIcon';
import { CloudIcon } from './components/icons/CloudIcon';

const LOCAL_STORAGE_KEY = 'expense-tracker-data';

const App: React.FC = () => {
  const [pendingTransactions, setPendingTransactions] = useState<Transaction[]>([]);
  const [unparseableTransactions, setUnparseableTransactions] = useState<UnparseableTransaction[]>([]);
  const [aiConfirmationQueue, setAiConfirmationQueue] = useState<AiConfirmationItem[]>([]);
  const [categorizedExpenses, setCategorizedExpenses] = useState<Expense[]>([]);
  const [budgets, setBudgets] = useState<Budgets>({});
  const [categories, setCategories] = useState<string[]>([...DEFAULT_EXPENSE_CATEGORIES]);
  const [customParsers, setCustomParsers] = useState<CustomParser[]>([]);
  const [roadmap, setRoadmap] = useState<RoadmapItem[]>([]);
  const [pendingTextTransactions, setPendingTextTransactions] = useState<string[]>([]);

  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [isSyncing, setIsSyncing] = useState<boolean>(false);
  const [syncError, setSyncError] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const [isSettingsOpen, setIsSettingsOpen] = useState<boolean>(false);
  const [isViewingLogs, setIsViewingLogs] = useState<boolean>(false);

  const [isAnalysisOpen, setIsAnalysisOpen] = useState<boolean>(false);
  const [initialAnalysisTab, setInitialAnalysisTab] = useState<'trends' | 'insights'>('trends');

  const [isAddingTransactions, setIsAddingTransactions] = useState<boolean>(false);
  const [isScanningReceipt, setIsScanningReceipt] = useState<boolean>(false);
  const [scanMode, setScanMode] = useState<'camera' | 'upload'>('camera');

  const [viewMode, setViewMode] = useState<'month' | 'week' | 'day'>('month');
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedWeekIndex, setSelectedWeekIndex] = useState(0);

  // Load data from Cloud API (with LocalStorage fallback)
  useEffect(() => {
    const initData = async () => {
        setIsLoading(true);
        logService.addLog("Attempting to load data from Cloud Storage...", "info");

        let loadedData: AppData | null = null;

        try {
            const response = await fetch('/api/data');
            if (response.ok) {
                const cloudData = await response.json();
                if (cloudData && Object.keys(cloudData).length > 0) {
                    loadedData = cloudData;
                    logService.addLog("Data successfully loaded from Cloud Storage.", "info");
                }
            }
        } catch (e) {
            console.warn("Could not fetch data from /api/data, falling back to local storage.", e);
            logService.addLog("Cloud fetch failed, checking local storage.", "info");
        }

        if (!loadedData) {
            try {
                const localDataString = localStorage.getItem(LOCAL_STORAGE_KEY);
                if (localDataString) {
                    loadedData = JSON.parse(localDataString);
                    logService.addLog("Data loaded from Local Storage.", "info");
                }
            } catch (e) {
                console.error("Failed to parse local storage data:", e);
            }
        }

        if (loadedData) {
            setCategorizedExpenses(loadedData.categorizedExpenses || []);
            setBudgets(loadedData.budgets || {});
            setCategories(loadedData.categories && loadedData.categories.length > 0 ? loadedData.categories : [...DEFAULT_EXPENSE_CATEGORIES]);
            setCustomParsers(loadedData.customParsers || []);
            setRoadmap(loadedData.roadmap || []);
        }

        setIsLoading(false);
    };

    initData();
  }, []);

  // Sync effect: LocalStorage + Cloud API
  useEffect(() => {
    if (isLoading) return;

    const handler = setTimeout(async () => {
        const dataToSave: AppData = {
            categorizedExpenses,
            budgets,
            categories,
            customParsers,
            roadmap,
        };

        // Update local storage first (instant)
        try {
            localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(dataToSave));
        } catch (e) {
            console.error("Local storage save failed", e);
        }

        // Push to cloud (background)
        setIsSyncing(true);
        setSyncError(false);
        try {
            const response = await fetch('/api/data', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(dataToSave)
            });
            if (!response.ok) throw new Error("Sync failed");
            logService.addLog("Data synchronized with cloud storage.", "info");
        } catch (e) {
            console.error("Cloud sync failed", e);
            setSyncError(true);
            logService.addLog("Cloud sync failed. Will retry on next change.", "error");
        } finally {
            setIsSyncing(false);
        }
    }, 1500);

    return () => clearTimeout(handler);
  }, [categorizedExpenses, budgets, categories, customParsers, roadmap, isLoading]);

  const hasNoData = useMemo(() => 
    pendingTransactions.length === 0 && 
    categorizedExpenses.length === 0 && 
    unparseableTransactions.length === 0 && 
    aiConfirmationQueue.length === 0, 
  [pendingTransactions, categorizedExpenses, unparseableTransactions, aiConfirmationQueue]);

  const weeksInMonth = useMemo(() => getWeeksInMonth(currentDate.getFullYear(), currentDate.getMonth()), [currentDate]);

  useEffect(() => {
    const today = new Date();
    if (today.getFullYear() === currentDate.getFullYear() && today.getMonth() === currentDate.getMonth()) {
        const weekIndex = weeksInMonth.findIndex(week => today >= week.start && today <= week.end);
        if (weekIndex !== -1) setSelectedWeekIndex(weekIndex);
    } else {
        setSelectedWeekIndex(0);
    }
  }, [currentDate, weeksInMonth]);

  const currentDateRange = useMemo(() => {
    if (viewMode === 'day') {
        const start = new Date(currentDate); start.setHours(0, 0, 0, 0);
        const end = new Date(currentDate); end.setHours(23, 59, 59, 999);
        return { start, end };
    }
    if (viewMode === 'month') {
      const start = new Date(currentDate.getFullYear(), currentDate.getMonth(), 1);
      const end = new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 0);
      end.setHours(23, 59, 59, 999);
      return { start, end };
    }
    return weeksInMonth[selectedWeekIndex] || { start: new Date(), end: new Date() };
  }, [viewMode, currentDate, selectedWeekIndex, weeksInMonth]);

  const isDateInCurrentRange = (dateString: string) => {
    const [year, month, day] = dateString.split('-').map(Number);
    const date = new Date(year, month - 1, day);
    const start = new Date(currentDateRange.start); start.setHours(0,0,0,0);
    return date >= start && date <= currentDateRange.end;
  };

  const visibleExpenses = useMemo(() => categorizedExpenses.filter(e => isDateInCurrentRange(e.date)), [categorizedExpenses, currentDateRange]);

  const currentAiConfirmation = aiConfirmationQueue.length > 0 ? aiConfirmationQueue[0] : null;
  const currentTransaction = pendingTransactions.length > 0 ? pendingTransactions[0] : null;
  const currentUnparseable = unparseableTransactions.length > 0 ? unparseableTransactions[0] : null;

  const chartData = useMemo(() => {
    const categoryTotals: { [key: string]: number } = {};
    visibleExpenses.forEach(expense => {
      categoryTotals[expense.category] = (categoryTotals[expense.category] || 0) + expense.amount;
    });
    return Object.entries(categoryTotals).map(([name, total]) => ({ name, total }));
  }, [visibleExpenses]);

  const processAllTransactions = useCallback(async () => {
    if (pendingTextTransactions.length === 0) return;

    setIsProcessing(true);
    setError(null);
    logService.addLog(`Starting to process ${pendingTextTransactions.length} transaction messages.`, 'info');

    const ruleBasedParser = await parseWithRules(customParsers);

    for (const text of pendingTextTransactions) {
        let parsed = false;

        const ruleResult = ruleBasedParser(text);
        if (ruleResult) {
            const id = crypto.randomUUID();
            setPendingTransactions(prev => [...prev, { id, ...ruleResult.data }]);
            logService.addLog(`Successfully parsed with rule: ${ruleResult.ruleName}`, 'info');
            parsed = true;
            continue;
        }

        try {
            const aiResult = await parseTransactionsFromText(text);
            if (aiResult.length > 0) {
                 const itemsForConfirmation: AiConfirmationItem[] = aiResult.map(parsedData => ({
                    id: crypto.randomUUID(),
                    originalText: text,
                    parsedData
                }));
                setAiConfirmationQueue(prev => [...prev, ...itemsForConfirmation]);
                parsed = true;
            }
        } catch (e: any) {
            console.error(e);
            logService.addLog(`AI parsing failed for text: "${text.substring(0, 50)}..."`, 'error');
        }

        if (!parsed) {
            const id = crypto.randomUUID();
            setUnparseableTransactions(prev => [...prev, { id, text }]);
            logService.addLog(`Failed to parse text: "${text.substring(0, 50)}..."`, 'info');
        }
    }

    setPendingTextTransactions([]);
    setIsProcessing(false);
    setIsAddingTransactions(false);
  }, [customParsers, pendingTextTransactions]);

  const handleCategorize = (transaction: Transaction, category: string) => {
    setCategorizedExpenses(prev => [...prev, { ...transaction, category }]);
    setPendingTransactions(prev => prev.filter(t => t.id !== transaction.id));
  };

  const handleIgnore = (id: string) => {
    setPendingTransactions(prev => prev.filter(t => t.id !== id));
  };

  const handleIgnoreUnparseable = (id: string) => {
    setUnparseableTransactions(prev => prev.filter(t => t.id !== id));
  };

  const handleManualAdd = (data: Omit<Transaction, 'id'>, unparseableId: string) => {
    const newTransaction: Transaction = {
        id: crypto.randomUUID(),
        ...data
    };
    setPendingTransactions(prev => [newTransaction, ...prev]);
    setUnparseableTransactions(prev => prev.filter(t => t.id !== unparseableId));
  };

  const handleAiConfirm = (idToConfirm: string, confirmedData: Omit<Transaction, 'id'>) => {
    const newTransaction: Transaction = {
        id: crypto.randomUUID(),
        ...confirmedData
    };
    setPendingTransactions(prev => [newTransaction, ...prev]);
    setAiConfirmationQueue(prev => prev.filter(item => item.id !== idToConfirm));
  };

  const handleAiDiscard = (idToDiscard: string) => {
      setAiConfirmationQueue(prev => prev.filter(item => item.id !== idToDiscard));
  };

  const handleReceiptParsed = (parsedData: Omit<Transaction, 'id'>, imageDataUrl: string) => {
    const newItem: AiConfirmationItem = {
      id: crypto.randomUUID(),
      imageDataUrl: imageDataUrl,
      parsedData: parsedData,
    };
    setAiConfirmationQueue(prev => [newItem, ...prev]);
    setIsScanningReceipt(false);
  };

  const handleDeleteExpense = (idToDelete: string) => {
    setCategorizedExpenses(prev => prev.filter(expense => expense.id !== idToDelete));
    logService.addLog(`Deleted expense with id: ${idToDelete}`, 'info');
  };

  const navigateDate = (direction: 'prev' | 'next') => {
    const increment = direction === 'next' ? 1 : -1;
    if (viewMode === 'week') {
        const newIndex = selectedWeekIndex + increment;
        if (newIndex >= 0 && newIndex < weeksInMonth.length) {
            setSelectedWeekIndex(newIndex);
        } else {
            setCurrentDate(prev => {
                const newDate = new Date(prev);
                newDate.setMonth(newDate.getMonth() + increment, 1);
                return newDate;
            });
        }
        return;
    }
    setCurrentDate(prevDate => {
        const newDate = new Date(prevDate);
        if (viewMode === 'day') newDate.setDate(newDate.getDate() + increment);
        else if (viewMode === 'month') newDate.setMonth(newDate.getMonth() + increment);
        return newDate;
    });
};

  const dateDisplay = useMemo(() => {
    if (viewMode === 'day') return currentDate.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
    if (viewMode === 'month') return currentDate.toLocaleDateString('en-US', { year: 'numeric', month: 'long' });
    if (weeksInMonth[selectedWeekIndex]) return formatDateRange(weeksInMonth[selectedWeekIndex].start, weeksInMonth[selectedWeekIndex].end);
    return '';
  }, [viewMode, currentDate, selectedWeekIndex, weeksInMonth]);

  const handleImportData = (data: AppData) => {
    setCategorizedExpenses(data.categorizedExpenses || []);
    setBudgets(data.budgets || {});
    setCategories(data.categories && data.categories.length > 0 ? data.categories : [...DEFAULT_EXPENSE_CATEGORIES]);
    setCustomParsers(data.customParsers || []);
    setRoadmap(data.roadmap || []);
    setIsSettingsOpen(false);
  };

  const handleExportJson = () => {
        const appData = { categorizedExpenses, budgets, categories, customParsers, roadmap };
        const jsonString = JSON.stringify(appData, null, 2);
        const blob = new Blob([jsonString], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = 'expense-tracker-data.json';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
  };

  if (isLoading) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-slate-50">
              <SpinnerIcon className="h-12 w-12 text-indigo-600" />
          </div>
      );
  }

  return (
    <div className="min-h-screen bg-slate-100">
      <header className="bg-white/80 backdrop-blur-lg sticky top-0 z-40 shadow-sm border-b border-slate-200">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex items-center justify-between h-16">
                <div className="flex items-center gap-3">
                    <LogoIcon />
                    <h1 className="text-xl font-bold text-slate-800">Expense Tracker</h1>
                </div>

                <div className="flex items-center gap-2">
                    <div className="mr-2 flex items-center" title={isSyncing ? "Saving to cloud..." : syncError ? "Sync failed" : "Data synced to cloud"}>
                        <CloudIcon className={`h-5 w-5 ${isSyncing ? 'text-indigo-400 animate-pulse' : syncError ? 'text-red-500' : 'text-green-500'}`} />
                    </div>
                    <button onClick={() => { setInitialAnalysisTab('trends'); setIsAnalysisOpen(true); }} className="p-2 rounded-full text-slate-600 hover:bg-slate-200 hover:text-slate-800 transition-colors" title="View Trends">
                        <TrendingUpIcon className="h-5 w-5"/>
                    </button>
                    <button onClick={handleExportJson} className="p-2 rounded-full text-slate-600 hover:bg-slate-200 hover:text-slate-800 transition-colors" title="Download Backup (JSON)">
                        <DownloadIcon className="h-5 w-5"/>
                    </button>
                    <button onClick={() => setIsViewingLogs(true)} className="p-2 rounded-full text-slate-600 hover:bg-slate-200 hover:text-slate-800 transition-colors" title="View Logs">
                        <LogIcon className="h-5 w-5"/>
                    </button>
                    <button onClick={() => setIsSettingsOpen(true)} className="p-2 rounded-full text-slate-600 hover:bg-slate-200 hover:text-slate-800 transition-colors" title="Settings">
                        <SettingsIcon className="h-5 w-5"/>
                    </button>
                     <button onClick={() => setIsAddingTransactions(true)} className="flex items-center gap-2 ml-2 px-4 py-2 text-sm font-semibold rounded-full text-white bg-indigo-600 hover:bg-indigo-700 transition-colors">
                        <PlusIcon className="h-5 w-5"/>
                        <span>Add</span>
                    </button>
                </div>
            </div>
        </div>
      </header>

      <main className="container mx-auto p-4 sm:p-6 lg:p-8">

        {isAddingTransactions && !isScanningReceipt && (
            <div className="mb-8">
                <MessageProcessor
                    onProcess={processAllTransactions}
                    isProcessing={isProcessing}
                    error={error}
                    onScanReceipt={() => { setScanMode('camera'); setIsScanningReceipt(true); }}
                    onUploadReceipt={() => { setScanMode('upload'); setIsScanningReceipt(true); }}
                    onClose={() => {
                        setIsAddingTransactions(false);
                        setPendingTextTransactions([]);
                    }}
                    transactionTexts={pendingTextTransactions}
                    setTransactionTexts={setPendingTextTransactions}
                />
            </div>
        )}

        {hasNoData && !isAddingTransactions && (
            <EmptyState onAddTransactions={() => setIsAddingTransactions(true)} />
        )}

        {!hasNoData && (
             <div className="space-y-8">
                <div className="bg-white/80 backdrop-blur-lg p-3 rounded-full shadow-md border border-slate-200/80 flex items-center justify-between">
                    <div className="flex items-center gap-1">
                        <button onClick={() => navigateDate('prev')} className="p-2 rounded-full hover:bg-slate-100 text-slate-600" title="Previous">
                            <ChevronLeftIcon />
                        </button>
                    </div>
                    <div className="flex-grow text-center">
                        <span className="font-semibold text-slate-700 mx-4">{dateDisplay}</span>
                        <div className="inline-flex p-1 bg-slate-200 rounded-full text-sm">
                            <button onClick={() => setViewMode('day')} className={`px-3 py-1 rounded-full font-semibold transition-colors ${viewMode === 'day' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-600'}`}>Day</button>
                            <button onClick={() => setViewMode('week')} className={`px-3 py-1 rounded-full font-semibold transition-colors ${viewMode === 'week' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-600'}`}>Week</button>
                            <button onClick={() => setViewMode('month')} className={`px-3 py-1 rounded-full font-semibold transition-colors ${viewMode === 'month' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-600'}`}>Month</button>
                        </div>
                    </div>
                     <div className="flex items-center gap-1">
                        <button onClick={() => navigateDate('next')} className="p-2 rounded-full hover:bg-slate-100 text-slate-600" title="Next">
                            <ChevronRightIcon />
                        </button>
                    </div>
                </div>

                {currentAiConfirmation ? (
                    <div className="p-6 bg-cyan-50 border-2 border-dashed border-cyan-200 rounded-2xl">
                        <h2 className="text-xl font-semibold text-cyan-800 mb-4">Confirm AI Suggestion ({aiConfirmationQueue.length} remaining)</h2>
                        <div className="max-w-2xl mx-auto">
                            <AiConfirmationCard
                                key={currentAiConfirmation.id}
                                item={currentAiConfirmation}
                                onConfirm={handleAiConfirm}
                                onDiscard={handleAiDiscard}
                            />
                        </div>
                    </div>
                ) : currentTransaction ? (
                    <div className="p-6 bg-indigo-50 border-2 border-dashed border-indigo-200 rounded-2xl">
                        <h2 className="text-xl font-semibold text-indigo-800 mb-4">Pending: {pendingTransactions.length}</h2>
                        <div className="max-w-2xl mx-auto">
                            <TransactionCard
                                key={currentTransaction.id}
                                transaction={currentTransaction}
                                onIgnore={() => handleIgnore(currentTransaction.id)}
                                onCategorize={(category) => handleCategorize(currentTransaction, category)}
                                categories={categories}
                            />
                        </div>
                    </div>
                ) : currentUnparseable ? (
                     <div className="p-6 bg-amber-50 border-2 border-dashed border-amber-200 rounded-2xl">
                        <h2 className="text-xl font-semibold text-amber-800 mb-4">Needs Attention: {unparseableTransactions.length}</h2>
                        <div className="max-w-2xl mx-auto">
                            <UnparseableTransactionCard
                                key={currentUnparseable.id}
                                item={currentUnparseable}
                                onIgnore={handleIgnoreUnparseable}
                                onManualAdd={handleManualAdd}
                            />
                        </div>
                    </div>
                ) : (
                     <div className="p-6 bg-green-50 border border-green-200 rounded-2xl flex flex-col items-center justify-center text-center">
                        <CheckCircleIcon />
                        <h2 className="text-xl font-semibold text-green-800 mt-4">All Caught Up!</h2>
                        <p className="text-green-700">You've categorized all transactions for this period.</p>
                     </div>
                )}

                <BudgetStatus expenses={visibleExpenses} budgets={budgets} />
                <ExpenseChart data={chartData} />
                <ExpenseSummary expenses={visibleExpenses} onDeleteExpense={handleDeleteExpense} />
            </div>
        )}
      </main>

      {isSettingsOpen && (
          <Settings 
              onClose={() => setIsSettingsOpen(false)}
              categories={categories}
              setCategories={setCategories}
              categorizedExpenses={categorizedExpenses}
              budgets={budgets}
              setBudgets={setBudgets}
              customParsers={customParsers}
              setCustomParsers={setCustomParsers}
              roadmap={roadmap}
              setRoadmap={setRoadmap}
              onImportData={handleImportData}
              onExportJson={handleExportJson}
          />
      )}
      {isViewingLogs && <LogViewer onClose={() => setIsViewingLogs(false)} />}
      {isAnalysisOpen && <Trends onClose={() => setIsAnalysisOpen(false)} initialTab={initialAnalysisTab} expenses={categorizedExpenses} categories={categories} />}
      {isScanningReceipt && <ReceiptScanner onClose={() => setIsScanningReceipt(false)} onReceiptParsed={handleReceiptParsed} initialMode={scanMode} />}
    </div>
  );
};

export default App;

export interface Transaction {
  id: string;
  merchant: string;
  amount: number;
  date: string;
}

export type ExpenseCategory = string;

export interface Expense extends Transaction {
  category: ExpenseCategory;
}

export interface CustomParser {
  id: string;
  name: string;
  template: string;
}

export interface UnparseableTransaction {
  id: string;
  text: string;
}

export type LogType = 'api' | 'info' | 'error';

export interface LogEntry {
  id: string;
  timestamp: Date;
  message: string;
  type: LogType;
}

export interface Budgets {
  [category: string]: number | undefined;
  overall?: number;
}

export interface RoadmapItem {
  id: string;
  text: string;
  isCompleted: boolean;
  createdAt: string;
}

export interface AppData {
  categorizedExpenses: Expense[];
  budgets: Budgets;
  categories: string[];
  customParsers: CustomParser[];
  roadmap?: RoadmapItem[];
}

export interface AiConfirmationItem {
  id: string;
  originalText?: string;
  imageDataUrl?: string;
  parsedData: Omit<Transaction, 'id'>;
}

export interface AuthState {
  isAuthenticated: boolean;
  vaultKey: string | null;
}

import React, { useState } from 'react';
import { LogoIcon } from './icons/LogoIcon';
import { SpinnerIcon } from './icons/SpinnerIcon';

interface LoginProps {
    onLogin: (password: string) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
    const [password, setPassword] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!password.trim()) return;

        setIsLoading(true);
        // Small delay for UX feel
        setTimeout(() => {
            onLogin(password);
            setIsLoading(false);
        }, 800);
    };

    return (
