// This is a Vercel Serverless Function that acts as a simple API
// for reading and writing the application's data to Vercel Blob storage.

import { put, head } from '@vercel/blob';

// Simple hash function for deriving filename from key
async function hashKey(key: string): Promise<string> {
    const encoder = new TextEncoder();
    const data = encoder.encode(key);
    const hashBuffer = await crypto.subtle.digest('SHA-256', data);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

export default async function handler(req: any, res: any) {
    const vaultKey = req.headers['x-vault-key'];
    const BLOB_TOKEN = process.env.BLOB_READ_WRITE_TOKEN;

    if (!BLOB_TOKEN) {
        return res.status(500).json({ error: 'The BLOB_READ_WRITE_TOKEN environment variable is not configured.' });
    }

    if (!vaultKey) {
        return res.status(401).json({ error: 'Vault key required' });
    }

    // Derive unique filename from the user's password/key
    const keyHash = await hashKey(vaultKey);
    const filename = `vault_${keyHash}.json`;

    // Vercel Blob API URLs are structured differently depending on usage, 
    // but using the @vercel/blob helper or direct fetch works.
    const BLOB_STORE_URL = `https://blob.vercel-storage.com/${filename}`;
    const headers = {
        'Authorization': `Bearer ${BLOB_TOKEN}`,
    };

    // GET /api/data - Retrieve the entire application state
    if (req.method === 'GET') {
        try {
            const blobResponse = await fetch(BLOB_STORE_URL, {
                method: 'GET',
                headers: headers,
            });

            if (blobResponse.status === 404) {
                return res.status(200).json({});
            }

            if (!blobResponse.ok) {
                 const errorText = await blobResponse.text();
                 throw new Error(`Failed to fetch data from blob: ${errorText}`);
            }

            const data = await blobResponse.json();
            return res.status(200).json(data);

        } catch (error: any) {
            console.error('Error fetching data from Vercel Blob:', error);
            return res.status(500).json({ error: `Failed to retrieve data: ${error.message}` });
        }
    }

    // POST /api/data - Save the entire application state
    if (req.method === 'POST') {
        try {
            const blobResponse = await fetch(BLOB_STORE_URL, {
                method: 'PUT',
                headers: {
                    ...headers,
                    'Content-Type': 'application/json',
                    'x-add-random-suffix': 'false', // Keep our derived filename exact
                },
                body: JSON.stringify(req.body),
            });

            if (!blobResponse.ok) {
                const errorText = await blobResponse.text();
                throw new Error(`Failed to upload data to blob: ${errorText}`);
            }

            const result = await blobResponse.json();
            return res.status(200).json({ success: true, ...result });

        } catch (error: any) {
            console.error('Error saving data to Vercel Blob:', error);
            return res.status(500).json({ error: `Failed to save data: ${error.message}` });
        }
    }

    res.setHeader('Allow', ['GET', 'POST']);
    return res.status(405).end(`Method ${req.method} Not Allowed`);
}

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { parseTransactionsFromText } from './services/geminiService';
import { parseWithRules } from './services/ruleBasedParsers';
