                <div className="flex items-center gap-3">
                    <LogoIcon />
                    <h1 className="text-xl font-bold text-slate-800">Expense Tracker</h1>
                </div>

                <div className="flex items-center gap-2">
                    <div className="mr-2 flex items-center" title={isSyncing ? "Saving to cloud..." : syncError ? "Sync failed" : "Data synced to cloud"}>
                        <CloudIcon className={`h-5 w-5 ${isSyncing ? 'text-indigo-400 animate-pulse' : syncError ? 'text-red-500' : 'text-green-500'}`} />
                    </div>
                    <button onClick={() => { setInitialAnalysisTab('trends'); setIsAnalysisOpen(true); }} className="p-2 rounded-full text-slate-600 hover:bg-slate-200 hover:text-slate-800 transition-colors" title="View Trends">
                        <TrendingUpIcon className="h-5 w-5"/>
                    </button>
                    <button onClick={handleExportJson} className="p-2 rounded-full text-slate-600 hover:bg-slate-200 hover:text-slate-800 transition-colors" title="Download Backup (JSON)">
                        <DownloadIcon className="h-5 w-5"/>
                    </button>
                    <button onClick={() => setIsViewingLogs(true)} className="p-2 rounded-full text-slate-600 hover:bg-slate-200 hover:text-slate-800 transition-colors" title="View Logs">
                        <LogIcon className="h-5 w-5"/>
                    </button>
                    <button onClick={() => setIsSettingsOpen(true)} className="p-2 rounded-full text-slate-600 hover:bg-slate-200 hover:text-slate-800 transition-colors" title="Settings">
                        <SettingsIcon className="h-5 w-5"/>
                    </button>
                    <button onClick={handleLogout} className="p-2 rounded-full text-slate-400 hover:text-red-500 transition-colors" title="Lock Vault">
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M16.5 10.5V6.75a4.5 4.5 0 10-9 0v3.75m-.75 11.25h10.5a2.25 2.25 0 002.25-2.25v-6.75a2.25 2.25 0 00-2.25-2.25H6.75a2.25 2.25 0 00-2.25 2.25v6.75a2.25 2.25 0 002.25 2.25z" />
                        </svg>
                    </button>
                     <button onClick={() => setIsAddingTransactions(true)} className="flex items-center gap-2 ml-2 px-4 py-2 text-sm font-semibold rounded-full text-white bg-indigo-600 hover:bg-indigo-700 transition-colors">
                        <PlusIcon className="h-5 w-5"/>
                        <span>Add</span>
                    </button>
                </div>
            </div>
        </div>
      </header>

      <main className="container mx-auto p-4 sm:p-6 lg:p-8">

        {isAddingTransactions && !isScanningReceipt && (
            <div className="mb-8">
                <MessageProcessor
                    onProcess={processAllTransactions}
                    isProcessing={isProcessing}
                    error={error}
                    onScanReceipt={() => { setScanMode('camera'); setIsScanningReceipt(true); }}
                    onUploadReceipt={() => { setScanMode('upload'); setIsScanningReceipt(true); }}
                    onClose={() => {
                        setIsAddingTransactions(false);
                        setPendingTextTransactions([]);
                    }}
                    transactionTexts={pendingTextTransactions}
                    setTransactionTexts={setPendingTextTransactions}
                />
            </div>
        )}

        {hasNoData && !isAddingTransactions && (
            <EmptyState onAddTransactions={() => setIsAddingTransactions(true)} />
        )}

        {!hasNoData && (
             <div className="space-y-8">
                <div className="bg-white/80 backdrop-blur-lg p-3 rounded-full shadow-md border border-slate-200/80 flex items-center justify-between">
                    <div className="flex items-center gap-1">
                        <button onClick={() => navigateDate('prev')} className="p-2 rounded-full hover:bg-slate-100 text-slate-600" title="Previous">
                            <ChevronLeftIcon />
                        </button>
                    </div>
                    <div className="flex-grow text-center">
                        <span className="font-semibold text-slate-700 mx-4">{dateDisplay}</span>
                        <div className="inline-flex p-1 bg-slate-200 rounded-full text-sm">
                            <button onClick={() => setViewMode('day')} className={`px-3 py-1 rounded-full font-semibold transition-colors ${viewMode === 'day' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-600'}`}>Day</button>
                            <button onClick={() => setViewMode('week')} className={`px-3 py-1 rounded-full font-semibold transition-colors ${viewMode === 'week' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-600'}`}>Week</button>
                            <button onClick={() => setViewMode('month')} className={`px-3 py-1 rounded-full font-semibold transition-colors ${viewMode === 'month' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-600'}`}>Month</button>
                        </div>
                    </div>
                     <div className="flex items-center gap-1">
                        <button onClick={() => navigateDate('next')} className="p-2 rounded-full hover:bg-slate-100 text-slate-600" title="Next">
                            <ChevronRightIcon />
                        </button>
                    </div>
                </div>

                {currentAiConfirmation ? (
                    <div className="p-6 bg-cyan-50 border-2 border-dashed border-cyan-200 rounded-2xl">
                        <h2 className="text-xl font-semibold text-cyan-800 mb-4">Confirm AI Suggestion ({aiConfirmationQueue.length} remaining)</h2>
                        <div className="max-w-2xl mx-auto">
                            <AiConfirmationCard
                                key={currentAiConfirmation.id}
                                item={currentAiConfirmation}
                                onConfirm={handleAiConfirm}
                                onDiscard={handleAiDiscard}
                            />
                        </div>
                    </div>
                ) : currentTransaction ? (
                    <div className="p-6 bg-indigo-50 border-2 border-dashed border-indigo-200 rounded-2xl">
                        <h2 className="text-xl font-semibold text-indigo-800 mb-4">Pending: {pendingTransactions.length}</h2>
                        <div className="max-w-2xl mx-auto">
                            <TransactionCard
                                key={currentTransaction.id}
                                transaction={currentTransaction}
                                onIgnore={() => handleIgnore(currentTransaction.id)}
                                onCategorize={(category) => handleCategorize(currentTransaction, category)}
                                categories={categories}
                            />
                        </div>
                    </div>
                ) : currentUnparseable ? (
                     <div className="p-6 bg-amber-50 border-2 border-dashed border-amber-200 rounded-2xl">
                        <h2 className="text-xl font-semibold text-amber-800 mb-4">Needs Attention: {unparseableTransactions.length}</h2>
                        <div className="max-w-2xl mx-auto">
                            <UnparseableTransactionCard
                                key={currentUnparseable.id}
                                item={currentUnparseable}
                                onIgnore={handleIgnoreUnparseable}
                                onManualAdd={handleManualAdd}
                            />
                        </div>
                    </div>
                ) : (
                     <div className="p-6 bg-green-50 border border-green-200 rounded-2xl flex flex-col items-center justify-center text-center">
                        <CheckCircleIcon />
                        <h2 className="text-xl font-semibold text-green-800 mt-4">All Caught Up!</h2>
                        <p className="text-green-700">You've categorized all transactions for this period.</p>
                     </div>
                )}

                <BudgetStatus expenses={visibleExpenses} budgets={budgets} />
                <ExpenseChart data={chartData} />
                <ExpenseSummary expenses={visibleExpenses} onDeleteExpense={handleDeleteExpense} />
            </div>
        )}
      </main>

      {isSettingsOpen && (
          <Settings 
              onClose={() => setIsSettingsOpen(false)}
              categories={categories}
              setCategories={setCategories}
              categorizedExpenses={categorizedExpenses}
              budgets={budgets}
              setBudgets={setBudgets}
              customParsers={customParsers}
              setCustomParsers={setCustomParsers}
              roadmap={roadmap}
              setRoadmap={setRoadmap}
              onImportData={handleImportData}
              onExportJson={handleExportJson}
          />
      )}
      {isViewingLogs && <LogViewer onClose={() => setIsViewingLogs(false)} />}
      {isAnalysisOpen && <Trends onClose={() => setIsAnalysisOpen(false)} initialTab={initialAnalysisTab} expenses={categorizedExpenses} categories={categories} />}
      {isScanningReceipt && <ReceiptScanner onClose={() => setIsScanningReceipt(false)} onReceiptParsed={handleReceiptParsed} initialMode={scanMode} />}
    </div>
  );
};

export default App;

